namespace sv_a81644f13dc049449f5681d3face6bac.Services;

public class WizardState
{
    // Step 1 — Personal Info
    public string FullName { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 — Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3 — References
    public List<ReferenceContact> References { get; set; } = [];

    // Track which steps the user has explicitly saved
    public HashSet<int> CompletedSteps { get; } = [];

    public event Action? OnChange;

    public void MarkStepCompleted(int step)
    {
        CompletedSteps.Add(step);
        OnChange?.Invoke();
    }
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav
@using sv_a81644f13dc049449f5681d3face6bac.Services

<PageTitle>Personal Info — Step 1 of 4</PageTitle>

<h1>Step 1: Personal Information</h1>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.FullName" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    private void Next()
    {
        Wizard.MarkStepCompleted(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav
@using sv_a81644f13dc049449f5681d3face6bac.Services

<PageTitle>Experience — Step 2 of 4</PageTitle>

<h1>Step 2: Experience</h1>

@foreach (var (job, i) in Wizard.JobHistory.Select((j, i) => (j, i)))
{
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Job @(i + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(i)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="job.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="job.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="job.Years" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex gap-2">
    <button type="button" class="btn btn-secondary" @onclick="Back">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override void OnInitialized()
    {
        if (Wizard.JobHistory.Count == 0)
            Wizard.JobHistory.Add(new JobEntry());
    }

    private void AddJob() => Wizard.JobHistory.Add(new JobEntry());

    private void RemoveJob(int index) => Wizard.JobHistory.RemoveAt(index);

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        Wizard.MarkStepCompleted(2);
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav
@using sv_a81644f13dc049449f5681d3face6bac.Services

<PageTitle>References — Step 3 of 4</PageTitle>

<h1>Step 3: References</h1>

@foreach (var (reference, i) in Wizard.References.Select((r, i) => (r, i)))
{
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Reference @(i + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(i)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="reference.Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="reference.Relationship" />
        </div>
        <div class="mb-2">
            <label class="form-label">Phone</label>
            <input class="form-control" @bind="reference.Phone" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add Reference</button>

<div class="d-flex gap-2">
    <button type="button" class="btn btn-secondary" @onclick="Back">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override void OnInitialized()
    {
        if (Wizard.References.Count == 0)
            Wizard.References.Add(new ReferenceContact());
    }

    private void AddRef() => Wizard.References.Add(new ReferenceContact());

    private void RemoveRef(int index) => Wizard.References.RemoveAt(index);

    private void Back() => Nav.NavigateTo("/apply/experience");

    private void Next()
    {
        Wizard.MarkStepCompleted(3);
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav
@using sv_a81644f13dc049449f5681d3face6bac.Services

<PageTitle>Review — Step 4 of 4</PageTitle>

<h1>Step 4: Review Your Application</h1>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <dl class="row mb-0">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@Wizard.FullName</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@Wizard.Email</dd>
    </dl>
</div>

<div class="card mb-3 p-3">
    <h5>Experience</h5>
    @if (Wizard.JobHistory.Count == 0)
    {
        <p class="text-muted">No jobs added.</p>
    }
    else
    {
        @foreach (var job in Wizard.JobHistory)
        {
            <dl class="row mb-2">
                <dt class="col-sm-3">Company</dt>
                <dd class="col-sm-9">@job.Company</dd>
                <dt class="col-sm-3">Title</dt>
                <dd class="col-sm-9">@job.Title</dd>
                <dt class="col-sm-3">Years</dt>
                <dd class="col-sm-9">@job.Years</dd>
            </dl>
            <hr />
        }
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (Wizard.References.Count == 0)
    {
        <p class="text-muted">No references added.</p>
    }
    else
    {
        @foreach (var r in Wizard.References)
        {
            <dl class="row mb-2">
                <dt class="col-sm-3">Name</dt>
                <dd class="col-sm-9">@r.Name</dd>
                <dt class="col-sm-3">Relationship</dt>
                <dd class="col-sm-9">@r.Relationship</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@r.Phone</dd>
            </dl>
            <hr />
        }
    }
</div>

<div class="d-flex gap-2">
    <button type="button" class="btn btn-secondary" @onclick="Back">← Back</button>
    <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        Wizard.MarkStepCompleted(4);
        // TODO: persist the application to a database
    }
}

