 ﻿@inherits LayoutComponentBase
 @inject NavigationManager Nav

 <div class="page">
     <div class="sidebar">
         <NavMenu />
     </div>

     <main>
         <div class="top-row px-4">
             @if (IsWizardPage)
             {
                 <nav class="wizard-progress" aria-label="Application progress">
                     @foreach (var step in Steps)
                     {
                         var css = step.Number == CurrentStep ? "active"
                                 : Progress?.IsCompleted(step.Number) == true ? "completed"
                                 : "";
                         <a href="@step.Href" class="wizard-step @css">
                             <span class="wizard-step-number">@step.Number</span>
                             <span class="wizard-step-label">@step.Label</span>
                         </a>
                     }
                     <span class="wizard-progress-text">Step @CurrentStep of @Steps.Length</span>
                 </nav>
             }
             else
             {
                 <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
             }
         </div>

         <article class="content px-4">
             @Body
         </article>
     </main>
 </div>

 <div id="blazor-error-ui" data-nosnippet>
