 @code {
     using sv_a81644f13dc049449f5681d3face6bac.Services;

     [CascadingParameter]
     private WizardProgress? Progress { get; set; }

     private static readonly (int Number, string Label, string Href)[] Steps =
     [
         (1, "Personal Info", "/apply/personal-info"),
         (2, "Experience",    "/apply/experience"),
         (3, "References",    "/apply/references"),
         (4, "Review",        "/apply/review"),
     ];

     private bool IsWizardPage => Nav.Uri.Contains("/apply/", StringComparison.OrdinalIgnoreCase);

     private int CurrentStep => Nav.Uri switch
     {
         var u when u.Contains("/personal-info", StringComparison.OrdinalIgnoreCase) => 1,
         var u when u.Contains("/experience", StringComparison.OrdinalIgnoreCase)    => 2,
         var u when u.Contains("/references", StringComparison.OrdinalIgnoreCase)    => 3,
         var u when u.Contains("/review", StringComparison.OrdinalIgnoreCase)        => 4,
         _ => 1,
     };
 }

